def split_words(txt):
    if ' ' in txt:
        return txt.split(' ')
    elif ',' in txt:
        return txt.split(',')
    else:
        count = 0
        for char in txt.lower():
            if char.isalpha():
                ord_value = ord(char) - ord('a')
                if ord_value % 2 == 1:
                    count += 1
        return count
